INSERT INTO estimulos_desenvolvimento (id,idade_inicial_meses,idade_final_meses,area,titulo,descricao,cuidado,fonte,versao_catalogo,ativo) VALUES
('20000000-0000-0000-0000-000000000201',2,3,'MOTOR','Tempo de bruços com presença','Em um momento de boa disposição, fique perto enquanto a criança permanece de bruços por períodos curtos e confortáveis.','Somente acordada, supervisionada e em superfície firme. Para dormir, sempre de barriga para cima.','Pikler/RIE + evidência atual sobre tummy time','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000202',2,3,'COGNITIVO','Siga o olhar com calma','Mova um chocalho leve e seguro devagar de um lado para outro, respeitando quando a criança perder o interesse.','Use objeto grande o suficiente para não oferecer risco de engasgo e interrompa se houver sobrecarga.','AAP Bright Futures','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000203',2,3,'LINGUAGEM_COMUNICACAO','Conversa de ida e volta','Repita um som que a criança fizer e faça uma pequena pausa, como se fosse a vez dela responder.','A atividade deve acompanhar o ritmo da criança, sem exigir resposta.','Vroom / Harvard Serve and Return','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000204',2,3,'SOCIAL_EMOCIONAL','Sorriso frente a frente','Em momentos tranquilos, aproxime seu rosto, sorria e espere a reação da criança antes de continuar a brincadeira.','Interrompa se ela desviar o olhar, chorar ou demonstrar cansaço.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000401',4,5,'MOTOR','Espaço livre para rolar','Ofereça um espaço firme no chão para a criança mover braços, pernas e tentar mudar de posição no próprio ritmo.','Evite posicionar sentada ou forçar movimentos que ela ainda não alcança sozinha.','Pikler/RIE','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000402',4,5,'COGNITIVO','Descobrir as próprias mãos','Coloque um guizo leve ou uma argola macia ao alcance das mãos para ela observar e explorar.','Use somente itens próprios para a idade, íntegros e supervisionados.','AAP Bright Futures','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000403',4,5,'LINGUAGEM_COMUNICACAO','Imite o arrulho','Imite o som que ela faz e aguarde alguns segundos. A pausa ajuda a transformar sons em troca.','Não há necessidade de repetir muitas vezes; poucos minutos já bastam.','Vroom / Harvard Serve and Return','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000404',4,5,'SOCIAL_EMOCIONAL','Careta no espelho','Faça expressões simples diante de um espelho seguro e observe juntas as reações.','Segure o espelho ou use material infantil seguro, sem vidro comum ao alcance.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000601',6,8,'MOTOR','Alcance no chão','Deixe um brinquedo seguro levemente ao lado para incentivar exploração e mudanças de posição sem conduzir o corpo.','Não force a criança a sentar; mantenha o ambiente livre de objetos pequenos.','Pikler/RIE','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000602',6,8,'COGNITIVO','Cadê o brinquedo?','Esconda parte de um brinquedo sob um pano leve e pergunte “cadê?”, deixando a descoberta acontecer.','Use pano respirável e nunca cubra o rosto da criança.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000603',6,8,'LINGUAGEM_COMUNICACAO','Responda ao balbucio','Trate o balbucio como uma conversa: responda com uma frase curta e espere a próxima tentativa.','A ideia é acompanhar a iniciativa da criança, não treiná-la.','Vroom / Harvard Serve and Return','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000604',6,8,'SOCIAL_EMOCIONAL','Imitação simples','Em uma brincadeira gostosa, bata palmas ou faça um gesto simples e comemore qualquer tentativa de participação.','Pare quando houver irritação ou cansaço; não é necessário insistir.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000901',9,11,'MOTOR','Deslocamento do próprio jeito','Organize um espaço seguro no chão para a criança rolar, arrastar-se ou engatinhar conforme sua própria forma de se mover.','Não é preciso forçar uma forma “correta” de engatinhar ou usar andadores.','Pikler/RIE','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000902',9,11,'COGNITIVO','Colocar e tirar','Ofereça um pote grande e objetos seguros para colocar e retirar repetidamente.','Evite peças pequenas, moedas, tampas ou qualquer item com risco de engasgo.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000903',9,11,'LINGUAGEM_COMUNICACAO','Nomeie o interesse','Quando a criança apontar, olhar ou vocalizar para algo, nomeie o objeto e espere sua reação.','Siga o interesse dela em vez de redirecionar a atividade.','Vroom','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000000904',9,11,'SOCIAL_EMOCIONAL','Toma lá, dá cá','Troquem um objeto seguro entre vocês, com pausas e sorrisos, para criar uma brincadeira de reciprocidade.','Mantenha o objeto grande, leve e adequado à idade.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001201',12,14,'MOTOR','Caminhar com liberdade','Ofereça espaço seguro para caminhar, cair e levantar no próprio ritmo.','Evite tapetes escorregadios, degraus sem proteção e conduzir a criança pelas mãos.','Pikler/RIE','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001202',12,14,'COGNITIVO','Encaixar e desencaixar','Explore potes e objetos de tamanhos diferentes para colocar, retirar e comparar.','Supervisione para que nenhum objeto seja levado à boca se não for seguro.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001203',12,14,'LINGUAGEM_COMUNICACAO','Livro compartilhado','Folheie um livro curto, nomeando figuras que chamam a atenção da criança.','Prefira livros resistentes e próprios para a idade; não há necessidade de concluir a história.','Vroom','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001204',12,14,'SOCIAL_EMOCIONAL','Valorize a tentativa','Nomeie e acolha pequenas tentativas de autonomia, como segurar a colher ou ajudar a se vestir.','Ofereça ajuda quando necessário e mantenha o ambiente seguro.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001501',15,17,'MOTOR','Degrau baixo com supervisão','Convide a criança a explorar um degrau baixo e estável, no ritmo dela, com você por perto.','Não puxe pelos braços; mantenha supervisão constante e superfície sem escorregar.','AAP Bright Futures','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001502',15,17,'COGNITIVO','Faz de conta simples','Brinque de dar comida a um boneco ou guardar um objeto, deixando a criança escolher como participar.','Use objetos grandes e seguros, sem peças pequenas destacáveis.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001503',15,17,'LINGUAGEM_COMUNICACAO','Pedido com pausa','Faça um pedido simples no dia a dia e espere alguns segundos antes de ajudar, valorizando gestos, sons e palavras.','A pausa é um convite, não uma cobrança.','Vroom','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001504',15,17,'SOCIAL_EMOCIONAL','Nomeie o carinho','Quando houver abraço, beijo ou proximidade, coloque em palavras o que está acontecendo.','Respeite quando a criança não quiser contato físico.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001801',18,20,'MOTOR','Bola leve no espaço aberto','Em local seguro, ofereça uma bola leve para correr, chutar ou empurrar livremente.','Afaste obstáculos e supervisione sempre; use bola grande demais para ser engolida.','AAP Bright Futures','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001802',18,20,'COGNITIVO','Sequência de faz de conta','Com um boneco, façam uma sequência simples: dar comida e depois colocar para dormir.','Deixe a criança mudar a sequência ou apenas observar.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001803',18,20,'LINGUAGEM_COMUNICACAO','Expanda uma palavra','Quando ela disser uma palavra, responda ampliando com uma frase curta e natural.','Fale de forma simples, sem pedir repetição.','Vroom','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000001804',18,20,'SOCIAL_EMOCIONAL','Nomeie as emoções','Na rotina, dê nome ao que a criança parece sentir e acolha a reação.','Evite interpretar como certeza; use frases abertas e gentis.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000002201',21,24,'MOTOR','Torre e bola','Ofereça blocos grandes para empilhar e uma bola leve para chutar, sem corrigir a tentativa.','Blocos devem ser grandes, íntegros e usados com supervisão.','AAP Bright Futures','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000002202',21,24,'COGNITIVO','Brincadeira em dois passos','Convide para uma sequência simples, como guardar a bola e depois fechar a caixa.','Transforme em brincadeira e ajude se a tarefa frustrar.','Portage Guide','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000002203',21,24,'LINGUAGEM_COMUNICACAO','Passeio com palavras','Em um passeio ou livro, nomeie objetos e faça perguntas abertas bem curtas.','Acompanhe o interesse da criança; o silêncio e a observação também fazem parte.','Vroom','ESTIMULOS_V1_2026_07',TRUE),
('20000000-0000-0000-0000-000000002204',21,24,'SOCIAL_EMOCIONAL','Cuidar do boneco','Inclua a criança em uma brincadeira de cuidado com boneco, respeitando a forma como ela escolhe participar.','Não use a brincadeira para cobrar comportamento; ela deve ser leve e compartilhada.','Zero to Three','ESTIMULOS_V1_2026_07',TRUE);
