CREATE TABLE estimulos_desenvolvimento (
    id UUID PRIMARY KEY, idade_inicial_meses INTEGER NOT NULL, idade_final_meses INTEGER NOT NULL,
    area VARCHAR(40) NOT NULL, titulo VARCHAR(140) NOT NULL, descricao VARCHAR(800) NOT NULL,
    cuidado VARCHAR(500) NOT NULL, fonte VARCHAR(180) NOT NULL, versao_catalogo VARCHAR(40) NOT NULL,
    ativo BOOLEAN NOT NULL,
    CONSTRAINT chk_estimulos_idade CHECK (idade_inicial_meses >= 0 AND idade_final_meses >= idade_inicial_meses),
    CONSTRAINT chk_estimulos_area CHECK (area IN ('SOCIAL_EMOCIONAL', 'LINGUAGEM_COMUNICACAO', 'COGNITIVO', 'MOTOR'))
);
CREATE TABLE registros_estimulos_desenvolvimento (
    id UUID PRIMARY KEY, crianca_id UUID NOT NULL, estimulo_id UUID NOT NULL, observacao VARCHAR(500), experimentado_em TIMESTAMP NOT NULL,
    CONSTRAINT fk_registros_estimulos_crianca FOREIGN KEY (crianca_id) REFERENCES criancas(id),
    CONSTRAINT fk_registros_estimulos_estimulo FOREIGN KEY (estimulo_id) REFERENCES estimulos_desenvolvimento(id),
    CONSTRAINT uq_registros_estimulos_crianca_estimulo UNIQUE (crianca_id, estimulo_id)
);
CREATE INDEX idx_estimulos_desenvolvimento_idade ON estimulos_desenvolvimento (idade_inicial_meses, idade_final_meses);

